#include<bits/stdc++.h>
using namespace std;
int b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long tag;
        bitset<31> val;
        node():tag(0){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].val=(a[a[x].lson].val|a[a[x].rson].val);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        if(!tg)
        {
            return;
        }
        a[ls].val=(1<<tg);
        a[rs].val=(1<<tg);
        a[ls].tag=tg;
        a[rs].tag=tg;
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].val=(1<<b[l]);
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].val=(1<<z);
            a[x].tag=z;
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    bitset<31> getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].val;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)|getsum(a[x].rson,l,r));
    }
}t;
int main()
{
    int n,m,q;
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=n;i++)
    {
        b[i]=1;
    }
    t.init(1,n);
    while(q--)
    {
        char p;
        int l,r,v;
        cin>>p>>l>>r;
        if(l>r)
        {
            swap(l,r);
        }
        if(p=='C')
        {
            cin>>v;
            t.update(1,l,r,v);
        }
        else
        {
            printf("%d\n",t.getsum(1,l,r).count());
        }
    }
    return 0;
}
